import bcrypt from "bcryptjs";
async function verifyPassword(password, hash) {
  if (!password || !hash) {
    return false;
  }
  try {
    if (hash.includes(":")) {
      logger.warn("[PasswordService] Tentative de v\xE9rification avec un ancien format de hash (pbkdf2). Rejet\xE9.");
      return false;
    }
    const isValid = await bcrypt.compare(password, hash);
    logger.debug("[PasswordService] V\xE9rification du mot de passe termin\xE9e", { isValid });
    return isValid;
  } catch (error) {
    logger.error("[PasswordService] Erreur lors de la v\xE9rification du mot de passe", { error });
    return false;
  }
}
