import { z as z32 } from "zod";
function paginate(data, total, input) {
  const totalPages = Math.ceil(total / input.limit);
  return {
    data,
    pagination: {
      page: input.page,
      limit: input.limit,
      total,
      totalPages,
      hasNext: input.page < totalPages,
      hasPrev: input.page > 1
    }
  };
}
