import { SignJWT as SignJWT2, jwtVerify as jwtVerify2 } from "jose";
async function createTenantToken(tenantId, userId, role) {
  const secretKey = new TextEncoder().encode(TENANT_JWT_SECRET || "dev-secret");
  const issuedAt = Date.now();
  return await new SignJWT2({ tenantId, userId, role, issuedAt }).setProtectedHeader({ alg: "HS256", typ: "JWT" }).setExpirationTime("30d").setIssuedAt(Math.floor(issuedAt / 1e3)).sign(secretKey);
}
function setTenantCookie(res, token) {
  res.cookie(TENANT_COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env["NODE_ENV"] === "production",
    sameSite: process.env["NODE_ENV"] === "production" ? "none" : "lax",
    maxAge: TENANT_COOKIE_MAX_AGE,
    path: "/"
  });
}
async function switchTenant(userId, tenantId, res) {
  const role = await getUserRoleInTenant(userId, tenantId);
  if (!role) return { success: false, error: "Acc\xE8s refus\xE9" };
  const token = await createTenantToken(tenantId, userId, role);
  setTenantCookie(res, token);
  return { success: true };
}
