async function sendEmail2(to, subject, body) {
  logger2.info(`[Email Service] Sending email to ${to}`);
  logger2.info(`[Email Service] Subject: ${subject}`);
  try {
    if (!process.env["EMAIL_PASSWORD"]) {
      logger2.info(`[Email Service] EMAIL_PASSWORD not configured, simulating send`);
      logger2.info(`[Email Service] Body: ${body}`);
      return Promise.resolve();
    }
    const info = await transporter.sendMail({
      from: `"Servicall CRM" <${process.env["EMAIL_USER"] || "servicallc@gmail.com"}>`,
      to,
      subject,
      text: body
    });
    logger2.info(`[Email Service] Email sent successfully: ${info.messageId}`);
  } catch (error) {
    logger2.error(`[Email Service] Error sending email:`, error);
    logger2.info(`[Email Service] Continuing despite email error`);
  }
}
